// items[0] = Slack search response
// items[1] = Open Tasks response
const items = $input.all();
const slack = items[0].json;
const openTasks = items[1].json;

if (!slack.ok) {
  return { to_process: [], skipped: [{ reason: 'Slack search failed: ' + (slack.error || 'unknown') }], skipped_count: 1, to_process_count: 0, slack_total: 0 };
}

const messages = (slack.messages && slack.messages.matches) || [];

// Dedupe by channel/ts
const existingKeys = new Set();
for (const page of (openTasks.results || [])) {
  const props = page.properties || {};
  const notes = ((props.Notes && props.Notes.rich_text) || []).map(t => t.plain_text || '').join('');
  for (const m of notes.matchAll(/Slack ts: ([^\s\n]+)\/([^\s\n]+)/g)) {
    existingKeys.add(`${m[1]}/${m[2]}`);
  }
}

const SELF = 'REPLACE_WITH_SLACK_USER_ID';
const toProcess = [];
const skipped = [];
for (const m of messages) {
  const key = `${m.channel && m.channel.id}/${m.ts}`;
  if (existingKeys.has(key)) { skipped.push({ reason: 'already harvested', ts: m.ts }); continue; }
  // Skip messages from Sales User himself — he's not asking himself anything
  if (m.user === SELF) { skipped.push({ reason: 'self-sent', ts: m.ts }); continue; }
  // Skip very short messages (likely reactions, not asks)
  if (!m.text || m.text.length < 20) { skipped.push({ reason: 'too short', ts: m.ts }); continue; }
  toProcess.push({
    ts: m.ts,
    channel_id: m.channel && m.channel.id,
    channel_name: m.channel && m.channel.name,
    user: m.user,
    username: m.username,
    text: m.text,
    permalink: m.permalink,
    iid: m.iid,
  });
}

return { to_process: toProcess, skipped, skipped_count: skipped.length, to_process_count: toProcess.length, slack_total: messages.length };

// Build the LLM prompt for one Slack message.

const msg = $json;

const prompt = `You are extracting action items from a Slack message that mentioned Sales User.

Channel: ${msg.channel_name || msg.channel_id || 'unknown'}
From: ${msg.username || msg.user || 'unknown'}
Timestamp: ${new Date(parseFloat(msg.ts) * 1000).toISOString()}
Permalink: ${msg.permalink}

Message:
${msg.text}

---

Determine whether this Slack message contains action items for Sales User or for someone else mentioned in it.

Skip (return empty action_items) if:
- The message is a casual reaction, social chatter, or kudos
- The message is FYI/notification with no ask
- The message is automated (bot, integration)
- The mention of Sales User is incidental (e.g., "thanks Sales User" without a follow-up ask)

For actionable messages, extract every action item. For each:
- text: the action item, rewritten as a concise imperative (≤120 chars)
- owner: "Sales User" if the sender is asking Sales User to do something. Otherwise the named person if a different owner is named, else "Unassigned".
- due_date: ISO date YYYY-MM-DD if mentioned, else null
- context: one short phrase (≤80 chars) explaining what the AI relates to

Project classification (pick ONE):
- Example Company Pipeline
- Example Company Business Development
- Corporate Development
- Content
- Operations
- Personal
- Non-Sales Admin
- Other

Return ONLY JSON:
{
  "project": "<one>",
  "summary": "<one-sentence summary, ≤180 chars>",
  "action_items": [
    {"text": "...", "owner": "Sales User", "due_date": null, "context": "..."}
  ]
}`;

return { msg, prompt };

const msg = $('Build prompt').item.json.msg;
const llm = $json || {};

let extracted = null;
let error = null;
try {
  const text = (llm.content || []).map(c => c.text || '').join('');
  const m = text.match(/\{[\s\S]*\}/);
  if (!m) throw new Error('no JSON in response');
  extracted = JSON.parse(m[0]);
} catch (e) {
  error = e.message;
}

if (error || !extracted) {
  return { skip: true, reason: error || 'parse failed', ts: msg.ts };
}

const ais = (extracted.action_items || []).filter(a => a && a.text && a.text.trim());
if (ais.length === 0) {
  return { skip: true, reason: 'no AIs extracted', ts: msg.ts, summary: extracted.summary };
}

const tsIso = new Date(parseFloat(msg.ts) * 1000).toISOString().slice(0, 10);
const ownerSet = [...new Set(ais.map(a => a.owner || 'Unassigned'))];
const sender = msg.username || msg.user || 'unknown';
const channel = msg.channel_name || msg.channel_id || 'unknown';
const titleBase = (((ais[0] || {}).text || '').trim() + (ais.length > 1 ? ' (+' + (ais.length - 1) + ' more)' : '')).slice(0, 190);

const notesLines = [];
notesLines.push(`Source URL: ${msg.permalink}`);
notesLines.push(`Slack ts: ${msg.channel_id}/${msg.ts}`);
notesLines.push(`Channel: ${channel}`);
notesLines.push(`From: ${sender}`);
notesLines.push(`Date: ${tsIso}`);
notesLines.push(`Summary: ${extracted.summary || ''}`);
notesLines.push('');
notesLines.push('Message snippet:');
notesLines.push(`> ${(msg.text || '').slice(0, 300)}`);
notesLines.push('');
notesLines.push('Action items:');
for (const a of ais) {
  const due = a.due_date ? ` (due ${a.due_date})` : '';
  notesLines.push(`- [${a.owner || 'Unassigned'}] ${a.text}${due}${a.context ? ` — ${a.context}` : ''}`);
}
const notesText = notesLines.join('\n').slice(0, 1990);

const validProjects = new Set(['Example Company Pipeline','Example Company Business Development','Corporate Development','Content','Operations','Personal','Non-Sales Admin']);
const projectName = validProjects.has(extracted.project) ? extracted.project : null;

const properties = {
  Task: { title: [{ text: { content: titleBase } }] },
  Status: { status: { name: 'Not started' } },
  Source: { rich_text: [{ text: { content: `Slack: #${channel} from ${sender}`.slice(0, 190) } }] },
  Notes: { rich_text: [{ text: { content: notesText } }] },
};
if (projectName) properties.Project = { select: { name: projectName } };

return {
  skip: false,
  ts: msg.ts,
  ai_count: ais.length,
  owners: ownerSet,
  notion_payload: {
    parent: { data_source_id: 'REPLACE_WITH_DATA_SOURCE_ID' },
    properties,
  },
  preview: { title: titleBase, notes: notesText.slice(0, 300) },
};

const out = [];
for (const item of $input.all()) {
  if (item.json && item.json.notion_payload && !item.json.skip) {
    out.push({ json: item.json });
  }
}
return out;

const created = $input.all().map(i => i.json);
const plan = $('Plan harvest').first().json;
const summary = {
  slack_total: plan.slack_total,
  to_process: plan.to_process_count,
  skipped_at_plan: plan.skipped_count,
  rows_created: created.length,
  generated_at: new Date().toISOString(),
};
return { summary, plan_skipped: plan.skipped, created };
